// Process scan result data
const data = $input.first().json.body;

// Validate required fields
if (!data.contract_address || !data.token_name) {
  return {
    status: 'error',
    message: 'Missing required fields'
  };
}

// Calculate risk score and emoji
const score = data.risk_score || 5;
let emoji = '✅';
let status = 'SAFE';

if (score >= 8) {
  emoji = '🚨';
  status = 'HIGH RISK';
} else if (score >= 5) {
  emoji = '⚠️';
  status = 'MODERATE RISK';
} else if (score >= 3) {
  emoji = '⚡';
  status = 'LOW RISK';
}

// Format contract address (shorten)
const contract = data.contract_address;
const shortContract = `${contract.slice(0, 6)}...${contract.slice(-4)}`

// Build issues list
let issuesText = '';
if (data.issues && data.issues.length > 0) {
  issuesText = data.issues.slice(0, 3).map(i => `❌ ${i}`).join('\n');
  if (data.issues.length > 3) {
  issuesText += `\n...and ${data.issues.length - 3} more`;
  }
}

// Format message
const message = `🔍 <b>Community Scan Result</b>

<b>${data.token_name}</b> <code>${shortContract}</code>

${emoji} Risk Score: <b>${score}/10</b> (${status})

${issuesText ? issuesText + '\n\n' : ''}Scanned by: @${data.username || 'anonymous'}
${data.scan_url ? `<a href="${data.scan_url}">View Full Report</a>` : ''}`;

return {
  status: 'success',
  message: message,
  risk_score: score,
  contract: contract
};

// Process backend health alert
const data = $input.first().json.body;

const alertTypes = {
  'error': { emoji: '🔴', priority: 'HIGH' },
  'warning': { emoji: '🟡', priority: 'MEDIUM' },
  'info': { emoji: '🔵', priority: 'LOW' },
  'system_down': { emoji: '🚨', priority: 'CRITICAL' },
  'webhook_fail': { emoji: '⚠️', priority: 'HIGH' },
  'db_error': { emoji: '💾', priority: 'CRITICAL' }
};

const type = data.alert_type || 'info';
const style = alertTypes[type] || alertTypes['info'];

const message = `${style.emoji} <b>Backend Alert</b> [${style.priority}]

<b>Type:</b> ${type.replace('_', ' ').toUpperCase()}
<b>Service:</b> ${data.service || 'Unknown'}
<b>Time:</b> ${new Date().toISOString()}

${data.message || data.error || 'No details provided'}

${data.action_required ? `<b>Action Required:</b> ${data.action_required}` : ''}`;

return {
  status: 'success',
  message: message,
  alert_type: type,
  priority: style.priority
};

// Process whale alert data
const data = $input.first().json.body;

// Validate required fields
if (!data.wallet_address || !data.amount) {
  return {
    status: 'error',
    message: 'Missing wallet_address or amount'
  };
}

// Calculate whale tier
const amount = parseFloat(data.amount);
let tier = 'small';
if (amount >= 1000000) tier = 'mega';
else if (amount >= 100000) tier = 'large';
else if (amount >= 10000) tier = 'medium';

// Format message
const formattedAmount = new Intl.NumberFormat('en-US', {
  style: 'currency',
  currency: 'USD',
  maximumFractionDigits: 0
}).format(amount);

return {
  status: 'success',
  wallet_address: data.wallet_address,
  amount: amount,
  formatted_amount: formattedAmount,
  tier: tier,
  token: data.token_symbol || 'UNKNOWN',
  chain: data.chain || 'solana',
  tx_hash: data.tx_hash || '',
  timestamp: new Date().toISOString(),
  alert_id: 'whale_' + Date.now()
};

