// Validate and process scam alert
const alert = $input.first().json.body;

// Validate required fields
if (!alert.token_address && !alert.contract_address) {
  return [{
    json: {
      success: false,
      error: 'Missing token or contract address'
    }
  }];
}

// Calculate risk score
let riskScore = alert.risk_score || 0;
if (alert.honeypot_detected) riskScore += 30;
if (alert.ownership_renounced === false) riskScore += 20;
if (alert.mint_function) riskScore += 25;
if (alert.sell_tax > 10) riskScore += 15;

return [{
  json: {
    ...alert,
    risk_score: Math.min(100, riskScore),
    processed_at: new Date().toISOString(),
    alert_level: riskScore >= 80 ? 'critical' : riskScore >= 60 ? 'high' : riskScore >= 40 ? 'medium' : 'low'
  }
}];

