// Format daily intelligence briefing
const briefing = $input.first().json.body;

const date = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

let message = `📊 **RMI Daily Intelligence - ${date}**\n\n`;

// Top Stories
if (briefing.top_stories && briefing.top_stories.length > 0) {
  message += `📰 **Top Stories**\n`;
  briefing.top_stories.slice(0, 3).forEach(story => {
    message += `• ${story.title}\n`;
  });
  message += `\n`;
}

// Scam Alerts
if (briefing.scam_alerts_count > 0) {
  message += `🚨 **Scam Alerts: ${briefing.scam_alerts_count} New**\n`;
  briefing.scam_alerts.slice(0, 2).forEach(alert => {
    message += `• ${alert.title}\n`;
  });
  message += `\n`;
}

// Trending Topics
if (briefing.trending_topics && briefing.trending_topics.length > 0) {
  message += `📈 **Trending Topics**\n`;
  briefing.trending_topics.slice(0, 3).forEach(topic => {
    message += `• ${topic.title}\n`;
  });
  message += `\n`;
}

// Pre-drafted content available
if (briefing.pre_drafted_posts_count > 0) {
  message += `✍️ **${briefing.pre_drafted_posts_count} Posts Ready to Publish**\n`;
  message += `Use /admin/intelligence/briefing to review\n\n`;
}

// Action items
if (briefing.admin_action_items && briefing.admin_action_items.length > 0) {
  message += `✅ **Action Items:**\n`;
  briefing.admin_action_items.slice(0, 3).forEach(item => {
    message += `□ ${item}\n`;
  });
}

message += `\n🔗 Full briefing: https://cryptorugmunch.com/admin/intelligence`;

return {
  message: message,
  raw_data: briefing
};

